-- #######################################################################################
-- AUTOGENERATED HYPR CONFIG (LUA).
-- PLEASE USE THE CONFIG PROVIDED IN THE GIT REPO /examples/hypr.conf AND EDIT IT,
-- OR EDIT THIS ONE ACCORDING TO THE WIKI INSTRUCTIONS.
-- #######################################################################################

-- This is an example Hyprland config in Lua format.
-- Refer to the wiki for more information.
-- https://wiki.hypr.land/

-- You can split this configuration into multiple files
-- Create your files separately and then source them:
-- source = ~/.config/hypr/myColors.conf

-- ################
-- ### MONITORS ###
-- ################

hl.monitor({
  output = "DP-2",
  mode = "3440x1440",
  position = "1920x0",
  scale = 1
})

hl.monitor({
  output = "HDMI-A-1",
  mode = "1920x1080",
  position = "0x500",
  scale = 1
})

-- ###################
-- ### MY PROGRAMS ###
-- ###################

-- https://wiki.hypr.land/Configuring/Keywords/
-- Set programs that you use
local terminal = "kitty"
local fileManager = "thunar"
local menu = "wofi --show drun --allow-images --insensitive --gtk-dark"

-- #################
-- ### AUTOSTART ###
-- #################

-- Autostart necessary processes (like notifications daemons, status bars, etc.)
-- Or execute your favorite apps at launch:
-- exec-once = $terminal
-- exec-once = nm-applet &
-- exec-once = waybar & hyprpaper & firefox

-- exec("waybar")
-- exec("hyprpaper")

-- #############################
-- ### ENVIRONMENT VARIABLES ###
-- #############################

-- https://wiki.hypr.land/Configuring/Environment-variables/
hl.env("XCURSOR_SIZE", "24")
hl.env("HYPRCURSOR_SIZE", "24")

-- #####################
-- ### LOOK AND FEEL ###
-- #####################

-- Refer to https://wiki.hypr.land/Configuring/Variables/

-- https://wiki.hypr.land/Configuring/Variables/#general
hl.config({
  general = {
    gaps_in = 4,
    gaps_out = 6,
    border_size = 1,
    col = {
      active_border = "rgba(33ccffee) rgba(00ff99ee) 45deg",
      inactive_border = "rgba(595959aa)",
    },
    resize_on_border = false,
    allow_tearing = false,
    layout = "dwindle"
  },

  -- https://wiki.hypr.land/Configuring/Variables/#decoration
  decoration = {
    rounding = 10,
    active_opacity = 1.0,
    inactive_opacity = 1.0,

    shadow = {
      enabled = true,
      range = 4,
      render_power = 3,
      color = "rgba(1a1a1aee)"
    }
  },

  -- https://wiki.hypr.land/Configuring/Variables/#blur
  blur = {
    enabled = true,
    size = 3,
    passes = 1,
    vibrancy = 0.1696
  }
})

-- https://wiki.hypr.land/Configuring/Variables/#animations
-- animations = {
--     enabled = true
--
--     -- Default animations, see https://wiki.hypr.land/Configuring/Animations/ for more
--     bezier = "myBezier", "0, 1, 0, 1"
--
--     animation = "windows", "1, 7, myBezier"
--     animation = "windowsOut", "1, 7, default, popin 80%"
