--     animation = "workspaces", "1, 6, myBezier"
--     animation = "specialWorkspace", "1, 6, myBezier"
--     animation = "specialWorkspaceOut", "1, 6, myBezier"
-- }

-- See https://wiki.hypr.land/Configuring/Dwindle-Layout/ for more
hl.config({
  dwindle = {
    preserve_split = false,
    smart_split = true
  }
})

-- See https://wiki.hypr.land/Configuring/Master-Layout/ for more
hl.config({
  master = {
    new_status = "master"
  }
})

-- https://wiki.hypr.land/Configuring/Variables/#misc
hl.config({
  misc = {
    force_default_wallpaper = -1
    disable_hyprland_logo = false
  }
})

-- #############
-- ### INPUT ###
-- #############

-- https://wiki.hypr.land/Configuring/Variables/#input
hl.config(
  {
    input = {
      kb_layout = "us,be",
      kb_options = "grp:lctrl_lwin_toggle",
      repeat_delay = 180,
      repeat_rate = 50,
      follow_mouse = true,
      sensitivity = 0,
      resolve_binds_by_sym = 1,
      numlock_by_default = true,

      touchpad = {
        natural_scroll = false
      }
    }
  })

-- Example per-device config
-- https://wiki.hypr.land/Configuring/Keywords/#per-device-input-configs for more
hl.deviced({
  name = "logitech-mx-anywhere-3"
  sensitivity = -0.2
})

-- ###################
-- ### KEYBINDINGS ###
-- ###################

-- See https://wiki.hypr.land/Configuring/Keywords/
-- $mainMod = SUPER # Sets "Windows" key as main modifier
local mainMod = "MOD1"


hl.bind(mainMod .. " + Q", "exec", terminal)
hl.bind(mainMod .. " + C", "killactive", "")
hl.bind(mainMod .. " +  SHIFT + M", "exec", "hyprctl dispatch exit")
hl.bind(mainMod .. " +  SHIFT + S", "exec", "systemctl suspend")
hl.bind(mainMod .. " +  SHIFT + Q", "exec", "shutdown -h now")
hl.bind(mainMod .. " +  CTRL + L", "exec", "hyprlock")
hl.bind(mainMod .. " + E", "exec", fileManager)
hl.bind(mainMod .. " + V", "togglefloating", "")
-- bind(mainMod .." + D", "exec", menu)
hl.bind(mainMod .. " + D", hl.dsp.exec_cmd(menu))
hl.bind(mainMod .. " + P", "pseudo", "# dwindle")
hl.bind(mainMod .. " + G", "layoutmsg", "togglesplit")

-- Move focus with mainMod + arrow keys
hl.bind(mainMod .. " + H", "movefocus", "l")
hl.bind(mainMod .. " + L", "movefocus", "r")
hl.bind(mainMod .. " + K", "movefocus", "u")
hl.bind(mainMod .. " + J", "movefocus", "d")

-- Swap window with mainMod + arrow keys
hl.bind(mainMod .. " +  SHIFT, H", "swapwindow", "l")
hl.bind(mainMod .. " +  SHIFT, L", "movewindow", "r")
hl.bind(mainMod .. " +  SHIFT, K", "movewindow", "u")
hl.bind(mainMod .. " +  SHIFT, J", "movewindow", "d")

-- Move workspace to monitor
hl.bind(mainMod .. " + , X", "movecurrentworkspacetomonitor", "0")
hl.bind(mainMod .. " + , Z", "movecurrentworkspacetomonitor", "1")

-- Switch workspaces with mainMod + [0-9]
hl.bind(mainMod .. " + 1", "workspace", "1")
hl.bind(mainMod .. " + 2", "workspace", "2")
hl.bind(mainMod .. " + 3", "workspace", "3")
hl.bind(mainMod .. " + 4", "workspace", "4")
hl.bind(mainMod .. " + 5", "workspace", "5")
hl.bind(mainMod .. " + 6", "workspace", "6")
hl.bind(mainMod .. " + 7", "workspace", "7")
hl.bind(mainMod .. " + 8", "workspace", "8")
hl.bind(mainMod .. " + 9", "workspace", "9")
hl.bind(mainMod .. " + 0", "workspace", "10")

-- Move active window to a workspace with mainMod + SHIFT + [0-9]
hl.bind(mainMod .. " +  SHIFT + 1", "movetoworkspacesilent", "1")
hl.bind(mainMod .. " +  SHIFT + 2", "movetoworkspacesilent", "2")
hl.bind(mainMod .. " +  SHIFT + 3", "movetoworkspacesilent", "3")
hl.bind(mainMod .. " +  SHIFT + 4", "movetoworkspacesilent", "4")
hl.bind(mainMod .. " +  SHIFT + 5", "movetoworkspacesilent", "5")
hl.bind(mainMod .. " +  SHIFT + 6", "movetoworkspacesilent", "6")
hl.bind(mainMod .. " +  SHIFT + 7", "movetoworkspacesilent", "7")
hl.bind(mainMod .. " +  SHIFT + 8", "movetoworkspacesilent", "8")
hl.bind(mainMod .. " +  SHIFT + 9", "movetoworkspacesilent", "9")
hl.bind(mainMod .. " +  SHIFT + 0", "movetoworkspacesilent", "10")

hl.bind(mainMod .. " + F", "fullscreen", "0")

-- Scroll through existing workspaces with mainMod + scroll
hl.bind(mainMod .. " + , mouse_down", "workspace", "e+1")
hl.bind(mainMod .. " + , mouse_up", "workspace", "e-1")

-- Move/resize windows with mainMod + LMB/RMB and dragging
hl.bind(mainMod .. " + , mouse:272", "movewindow", "")
hl.bind(mainMod .. " + , mouse:273", "resizewindow", "")

